fn run() {
    input! {
        x: i64,
        y: i64,
        z: i64,
    }
    let mut ans = 2 * z;
    let v = std::cmp::min(x, y);
    ans += 2 * v;
    if x > v {
        ans += 1;
    }
    if y > v {
        ans += 1;
    }
    println!("{}", ans);
}

fn main() {
    run();
}
